// Extract unique external domains from attendee emails
const input = $input.first().json;
const attendeesRaw = input.attendees || '[]';
const attendees = typeof attendeesRaw === 'string' ? JSON.parse(attendeesRaw) : attendeesRaw;
const internalDomains = ['gmail.com','yahoo.com','outlook.com','hotmail.com','3cventures.com','ahbadvisors.com','clientcatalyzer.com','icloud.com','me.com'];

const domains = [...new Set(
  attendees
    .map(a => a.email?.split('@')[1]?.toLowerCase())
    .filter(d => d && !internalDomains.includes(d))
)];

const contactEmails = attendees
  .filter(a => {
    const domain = a.email?.split('@')[1]?.toLowerCase();
    return domain && !internalDomains.includes(domain);
  })
  .map(a => a.email.toLowerCase());

return {
  domains: domains,
  contactEmails: contactEmails,
  primaryContactEmail: contactEmails[0] || '',
  attendeeCount: contactEmails.length,
  meetingTitle: input.meetingTitle,
  meetingTime: input.meetingTime,
  eventId: input.eventId,
  pass: input.pass,
  existingAgendaTaskId: input.existingAgendaTaskId || '',
  existingDescription: input.existingDescription || '',
  providedClientName: input.clientName || ''
};

// Match attendee domains against client CRM DataTable
// Field names: ClickUp_LIst_ID, Email_Domains, missive_label_id, company_name
const clientRows = $('Lookup All Clients').all();
const inputData = $('Extract Domains').first().json;

// Helper to read field with fallback names
function getField(row, ...names) {
  for (const n of names) {
    if (row.json[n] !== undefined && row.json[n] !== null && row.json[n] !== '') return row.json[n];
  }
  return '';
}

// If clientName was provided directly (delta refresh), match by name
if (inputData.providedClientName && inputData.providedClientName !== '') {
  const match = clientRows.find(r =>
    getField(r, 'company_name', 'name').toLowerCase() === inputData.providedClientName.toLowerCase()
  );
  if (match) {
    return {
      clientName: getField(match, 'company_name', 'name'),
      clientListId: getField(match, 'ClickUp_LIst_ID', 'clickup_list_id'),
      missiveLabelId: getField(match, 'missive_label_id'),
      clientFound: true,
      ...inputData
    };
  }
}

// Otherwise, match by domain
const domains = inputData.domains || [];
for (const domain of domains) {
  const match = clientRows.find(r => {
    const emailDomains = getField(r, 'Email_Domains', 'email_domains').toLowerCase();
    return emailDomains.split('|').some(d => d === domain || domain.endsWith('.' + d) || d.endsWith('.' + domain));
  });
  if (match) {
    return {
      clientName: getField(match, 'company_name', 'name'),
      clientListId: getField(match, 'ClickUp_LIst_ID', 'clickup_list_id'),
      missiveLabelId: getField(match, 'missive_label_id'),
      clientFound: true,
      matchedDomain: domain,
      ...inputData
    };
  }
}

// No match found
return {
  clientName: 'Unknown',
  clientListId: '',
  missiveLabelId: '',
  clientFound: false,
  ...inputData
};

// Build Missive API URL dynamically
// Priority: shared_label (precise) > email search > client name search
const client = $('Resolve Client').first().json;
const missiveLabelId = client.missiveLabelId || '';
const primaryEmail = client.primaryContactEmail || '';
const clientName = client.clientName || '';
const orgId = 'c7be17b4-c416-4d3a-b20d-62a89a261016';

const params = [];
params.push('organization=' + orgId);
params.push('limit=10');

if (missiveLabelId) {
  // Best: filter by client-specific Missive label
  params.push('shared_label=' + missiveLabelId);
} else if (primaryEmail) {
  // Fallback: search by contact email
  params.push('email=' + encodeURIComponent(primaryEmail));
} else if (clientName && clientName !== 'Unknown') {
  // Last resort: search by domain if available
  const domains = client.domains || [];
  if (domains.length > 0) {
    params.push('domain=' + encodeURIComponent(domains[0]));
  }
}

// Need at least one mailbox filter when not using shared_label
if (!missiveLabelId) {
  params.push('all=true');
}

return {
  emailApiUrl: 'https://public.missiveapp.com/v1/conversations?' + params.join('&'),
  searchMethod: missiveLabelId ? 'label' : (primaryEmail ? 'email' : 'domain')
};

// Merge all context into a single object for the AI synthesizer
// Separates active tasks from recently closed (last 7 days)
const clientData = $('Resolve Client').first().json;
const sevenDaysAgo = Date.now() - 7 * 24 * 60 * 60 * 1000;

// Get tasks — separate active vs recently closed
let activeTasks = [];
let recentlyClosedTasks = [];
try {
  const taskData = $('Get Client Tasks').first().json;
  const allTasks = taskData.tasks || [];
  for (const t of allTasks) {
    const taskObj = {
      id: t.id,
      name: t.name,
      status: t.status?.status || 'unknown',
      statusType: t.status?.type || 'open',
      dueDate: t.due_date ? new Date(parseInt(t.due_date)).toISOString().split('T')[0] : 'no due date',
      priority: t.priority?.priority || 'none',
      assignees: (t.assignees || []).map(a => a.username || a.email).join(', '),
      description: (t.description || '').substring(0, 200),
      dateClosed: t.date_closed || null
    };
    if (t.status?.type === 'closed') {
      const closedTime = parseInt(t.date_closed) || 0;
      if (closedTime > sevenDaysAgo) {
        recentlyClosedTasks.push(taskObj);
      }
    } else {
      activeTasks.push(taskObj);
    }
  }
} catch(e) {
  try {
    activeTasks = $('No Tasks (No List)').first().json.tasks || [];
  } catch(e2) {}
}

// Get meeting notes
let meetingNotes = [];
try {
  meetingNotes = $('Get Recent Meeting Notes').all().map(item => ({
    name: item.json.name,
    date: item.json.date,
    overview: item.json.overview,
    taskId: item.json.taskId,
    notesUrl: item.json.notesUrl
  }));
} catch(e) {}

// Get emails — filter out meeting invites/responses
const excludeLabelIds = ['65ead274-5239-4664-af8d-e98ce0009f92', '6fa6d7cf-ed52-481a-a743-561e560d6f17'];
let emails = [];
try {
  const emailData = $('Get Recent Emails').first().json;
  const allConvos = emailData.conversations || [];
  emails = allConvos
    .filter(c => {
      const convLabelIds = (c.shared_labels || []).map(l => l.id);
      return !excludeLabelIds.some(id => convLabelIds.includes(id));
    })
    .slice(0, 10)
    .map(c => ({
      subject: c.latest_message_subject || '(no subject)',
      date: c.last_activity_at,
      from: (c.external_authors && c.external_authors[0]) ? c.external_authors[0].address : '',
      fromName: (c.external_authors && c.external_authors[0]) ? c.external_authors[0].name : '',
      url: c.web_url || ('https://mail.missiveapp.com/#inbox/conversations/' + c.id)
    }));
} catch(e) {}

// Get newsletters
let newsletters = [];
try {
  newsletters = $('Get Newsletter Briefs').all().map(item => ({
    name: item.json.name,
    description: (item.json.description || '').substring(0, 300),
    dateCreated: item.json.date_created
  }));
} catch(e) {}

// Get email search method
let emailSearchMethod = 'unknown';
try {
  emailSearchMethod = $('Build Email Query').first().json.searchMethod || 'unknown';
} catch(e) {}

// Compute hashes for delta detection
const allTasksForHash = [...activeTasks, ...recentlyClosedTasks];
const tasksHash = allTasksForHash.map(t => t.id + ':' + t.status).sort().join('|');
const latestEmailTimestamp = emails.length > 0 ? emails[0].date : '';
const latestMeetingNoteId = meetingNotes.length > 0 ? (meetingNotes[0].taskId || '') : '';

return {
  contextJson: JSON.stringify({
    client: clientData.clientName,
    meetingTitle: clientData.meetingTitle,
    meetingTime: clientData.meetingTime,
    activeTasks: activeTasks,
    recentlyClosedTasks: recentlyClosedTasks,
    recentMeetingNotes: meetingNotes,
    recentEmails: emails,
    newsletters: newsletters,
    emailSearchMethod: emailSearchMethod
  }),
  clientName: clientData.clientName,
  clientListId: clientData.clientListId || '',
  missiveLabelId: clientData.missiveLabelId || '',
  meetingTitle: clientData.meetingTitle,
  meetingTime: clientData.meetingTime,
  eventId: clientData.eventId,
  pass: clientData.pass,
  existingAgendaTaskId: clientData.existingAgendaTaskId,
  existingDescription: clientData.existingDescription,
  tasksHash: tasksHash,
  latestEmailTimestamp: latestEmailTimestamp,
  latestMeetingNoteId: latestMeetingNoteId,
  taskCount: activeTasks.length,
  closedTaskCount: recentlyClosedTasks.length,
  noteCount: meetingNotes.length,
  emailCount: emails.length,
  newsletterCount: newsletters.length
};

// Section-based merge — protects manual edits and Relay template
// Includes AI brief + raw reference section with actual tasks, emails, notes
const mergeCtx = $('Merge All Context').first().json;
const existingDesc = mergeCtx.existingDescription || '';
const autoContent = $input.first().json.output || $input.first().json.text || '';
const pass = mergeCtx.pass;
const now = new Date().toLocaleString('en-US', {
  timeZone: 'America/New_York',
  month: 'short', day: 'numeric', year: 'numeric',
  hour: 'numeric', minute: '2-digit', hour12: true
});

const passLabel = {
  'day-before': 'Day-Before Build',
  'day-of': 'Day-Of Refresh',
  'pre-meeting': 'Pre-Meeting Update'
}[pass] || pass;

// Parse raw context for reference section
const ctx = JSON.parse(mergeCtx.contextJson || '{}');

// --- Build raw reference section ---
let rawRef = '\n\n---\n\n### Reference\n';

// Active + recently closed tasks
const activeTasks = ctx.activeTasks || [];
const closedTasks = ctx.recentlyClosedTasks || [];
if (activeTasks.length > 0 || closedTasks.length > 0) {
  rawRef += '\n**Tasks** (' + activeTasks.length + ' active';
  if (closedTasks.length > 0) rawRef += ', ' + closedTasks.length + ' recently closed';
  rawRef += '):\n';
  for (const t of activeTasks) {
    rawRef += '- [ ] ' + t.name + ' (CU-' + t.id + ') — ' + t.status;
    if (t.dueDate && t.dueDate !== 'no due date') rawRef += ' — Due ' + t.dueDate;
    rawRef += '\n';
  }
  for (const t of closedTasks) {
    rawRef += '- [x] ' + t.name + ' (CU-' + t.id + ') — closed';
    if (t.dateClosed) {
      try { rawRef += ' ' + new Date(parseInt(t.dateClosed)).toISOString().split('T')[0]; } catch(e) {}
    }
    rawRef += '\n';
  }
}

// Recent emails (3-5, cap at 5)
const emails = (ctx.recentEmails || []).slice(0, 5);
if (emails.length > 0) {
  rawRef += '\n**Recent Emails** (' + emails.length + '):\n';
  for (const e of emails) {
    let dateStr = '';
    if (e.date) {
      try {
        const d = typeof e.date === 'number' ? new Date(e.date * 1000) : new Date(e.date);
        dateStr = d.toLocaleDateString('en-US', { month: 'short', day: 'numeric' });
      } catch(err) {}
    }
    rawRef += '- \"' + (e.subject || '(no subject)') + '\"';
    if (e.fromName) rawRef += ' — ' + e.fromName;
    else if (e.from) rawRef += ' — ' + e.from;
    if (dateStr) rawRef += ' — ' + dateStr;
    if (e.url) rawRef += ' [view](' + e.url + ')';
    rawRef += '\n';
  }
}

// Past meetings (2-3, cap at 3)
const notes = (ctx.recentMeetingNotes || []).slice(0, 3);
if (notes.length > 0) {
  rawRef += '\n**Past Meetings** (' + notes.length + '):\n';
  for (const n of notes) {
    rawRef += '- ' + (n.name || 'Meeting');
    if (n.date) rawRef += ' — ' + n.date;
    if (n.notesUrl) rawRef += ' [notes](' + n.notesUrl + ')';
    rawRef += '\n';
    if (n.overview) {
      const overview = n.overview.length > 200 ? n.overview.substring(0, 200) + '...' : n.overview;
      rawRef += '  > ' + overview + '\n';
    }
  }
}

const stats = `${mergeCtx.taskCount} tasks | ${mergeCtx.closedTaskCount} recently closed | ${mergeCtx.noteCount} past meetings | ${mergeCtx.emailCount} emails`;

const autoSection = `\n\n---\n\n**Abel Context** — Last updated: ${now} ET (${passLabel}) — ${stats}\n\n${autoContent}${rawRef}\n\n**— End Abel Context —**`;

const START_MARKER = '**Abel Context**';
const END_MARKER = '**— End Abel Context —**';

const startIdx = existingDesc.indexOf(START_MARKER);
const endIdx = existingDesc.indexOf(END_MARKER);

let finalDescription;

if (startIdx === -1) {
  finalDescription = existingDesc + autoSection;
} else {
  const before = existingDesc.substring(0, existingDesc.lastIndexOf('\n', startIdx) > -1 ? existingDesc.lastIndexOf('\n', startIdx) : startIdx);
  const after = existingDesc.substring(endIdx + END_MARKER.length);
  finalDescription = before + autoSection + after;
}

return {
  description: finalDescription,
  clientName: mergeCtx.clientName,
  clientListId: mergeCtx.clientListId,
  missiveLabelId: mergeCtx.missiveLabelId || '',
  meetingTitle: mergeCtx.meetingTitle,
  meetingTime: mergeCtx.meetingTime,
  eventId: mergeCtx.eventId,
  pass: mergeCtx.pass,
  existingAgendaTaskId: mergeCtx.existingAgendaTaskId,
  tasksHash: mergeCtx.tasksHash,
  latestEmailTimestamp: mergeCtx.latestEmailTimestamp,
  latestMeetingNoteId: mergeCtx.latestMeetingNoteId
};

// Prepare output for DataTable tracking and parent workflow
const mergeData = $('Merge Description').first().json;
const taskId = mergeData.existingAgendaTaskId;
const attendees = $('Input').first().json.attendees || '[]';

return {
  eventId: mergeData.eventId,
  agendaTaskId: taskId,
  clientName: mergeData.clientName,
  clientListId: mergeData.clientListId || '',
  missiveLabelId: mergeData.missiveLabelId || '',
  meetingTitle: mergeData.meetingTitle,
  meetingTime: mergeData.meetingTime,
  attendees: attendees,
  pass: mergeData.pass,
  tasksHash: mergeData.tasksHash,
  latestEmailTimestamp: mergeData.latestEmailTimestamp,
  latestMeetingNoteId: mergeData.latestMeetingNoteId,
  lastRefreshed: new Date().toISOString()
};
